def tokenize(s):
    s_norm = normalize_ar(s)
    return s_norm.split()

def token_f1(a,b):
    ta=set(tokenize(a)); tb=set(tokenize(b))
    if not ta or not tb:
        return 0.0
    inter = len(ta & tb)
    prec = inter/len(ta)
    rec = inter/len(tb)
    if prec+rec==0: 
        return 0.0
    return 2*prec*rec/(prec+rec)

